#include <stdio.h>
int main() {
    int M, N, C;
    scanf("%d %d", &M, &N);
    int prefixSum[M + 1][N + 1] = {0};
    for (int i = 1; i <= M; i++) {
        for (int j = 1; j <= N; j++) {
            int volume;
            scanf("%d", &volume);
            prefixSum[i][j] = prefixSum[i - 1][j] + prefixSum[i][j - 1] - prefixSum[i - 1][j - 1] + volume;
        }
    }
    scanf("%d", &C);
    for (int i = 0; i < C; i++) {
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        int totalVolume = prefixSum[x2][y2] - prefixSum[x1 - 1][y2] - prefixSum[x2][y1 - 1] + prefixSum[x1 - 1][y1 - 1];
        printf("%d\n", totalVolume);
    }
    return 0;
}

